 1→import { readFileSync, writeFileSync, existsSync } from 'fs'
 2→import { join } from 'path'
 3→
 4→const CONFIG_PATH = join(process.env.HOME || '', '.greg-config.json')
 5→
 6→interface GregConfig {
 7→  contactsDir: string
 8→}
 9→
10→function defaultConfig(): GregConfig {
11→  return { contactsDir: join(process.env.HOME || '', 'greg-contacts') }
12→}
13→
14→export function getConfig(): GregConfig {
15→  try {
16→    if (existsSync(CONFIG_PATH)) {
17→      return { ...defaultConfig(), ...JSON.parse(readFileSync(CONFIG_PATH, 'utf-8')) }
18→    }
19→  } catch { /* ignore parse errors */ }
20→  return defaultConfig()
21→}
22→
23→export function saveConfig(updates: Partial<GregConfig>): GregConfig {
24→  const current = getConfig()
25→  const next = { ...current, ...updates }
26→  writeFileSync(CONFIG_PATH, JSON.stringify(next, null, 2), 'utf-8')
27→  return next
28→}
29→
30→export function getContactsDir(): string {
31→  return getConfig().contactsDir
32→}
